import DOM_SELECTORS from "../selectors/googlePaySelectorsMap";
import BasePaymentService from "./BasePaymentService";
import { loadExternalScript } from "../utils/loadExternalScript";

class GooglePayService extends BasePaymentService {
    constructor(config) {
        super();

        const {
            merchantId,
            mode = 'sandbox',
            options
        } = config;

        const { google } = options;
        const { googleMerchantId, googleMerchantName } = google;

        this.env = mode === 'sandbox' ? 'TEST' : 'PRODUCTION';
        this.debug = mode === 'sandbox';
        this.buttonWrapper = DOM_SELECTORS.PRZELEWY24_GOOGLE_PAY_WRAPPER;

        this.merchantId = merchantId;

        this.tokenizationParams = {
            gateway: 'przelewy24',
            gatewayMerchantId: this.merchantId.toString()
        };

        this.merchantInfo = {
            merchantName: googleMerchantName
        };

        this.allowedAuthMethods = ["PAN_ONLY", "CRYPTOGRAM_3DS"];
        this.allowedCardNetworks = ["AMEX", "DISCOVER", "JCB", "MASTERCARD", "VISA"];
    }

    async init() {
        await loadExternalScript('google-pay', 'https://pay.google.com/gp/p/js/pay.js', () => this.createClient());
    }

    async isPaymentAvailable() {
        const client = this.createClient();

        if (!client) {
            return false;
        }

        try {
            const { result = false } = await client.isReadyToPay(this.getBasePaymentRequest());
            return result;
        } catch (error) {
            return false;
        }
    }

    createClient() {
        if (this.paymentClient === null && window.google?.payments) {
            this.paymentClient = new google.payments.api.PaymentsClient(this.getClientConfig());
        }

        return this.paymentClient;
    }

    createPaymentButton(onClick) {
        const client = this.createClient();

        if (!client) {
            return false;
        }

        const button = client.createButton({
            buttonType: 'long',
            onClick
        });

        const wrapper = document.querySelector(this.buttonWrapper);
        wrapper && wrapper.appendChild(button);

        return true;
    }

    getClientConfig() {
        const { merchantInfo } = this;

        const config = {
            environment: this.env,
            merchantInfo
        };

        this.debug && console.log('Client config:', config);

        return config;
    }

    getBasePaymentRequest() {
        const {
            tokenizationParams,
            allowedAuthMethods,
            allowedCardNetworks
        } = this;

        const request = {
            apiVersion: 2,
            apiVersionMinor: 0,
            allowedPaymentMethods: [{
                type: 'CARD',
                parameters: {
                    allowedAuthMethods: allowedAuthMethods,
                    allowedCardNetworks: allowedCardNetworks
                },
                tokenizationSpecification: {
                    type: 'PAYMENT_GATEWAY',
                    parameters: tokenizationParams
                }
            }]
        };

        this.debug && console.log('Base payment data', request);

        return request;
    }

    getPaymentRequest() {
        const { merchantInfo, paymentDetails } = this;
        const { total, currency } = paymentDetails;

        const request = {
            ...this.getBasePaymentRequest(),
            merchantInfo,
            transactionInfo: {
                currencyCode: currency,
                totalPriceStatus: 'FINAL',
                totalPrice: total
            }
        };

        this.debug && console.log('Payment request', request);

        return request;
    }

    async processPayment() {
        this.reset();
        const client = this.createClient();

        try {
            const result = await client.loadPaymentData(this.getPaymentRequest());
            this.token = result.paymentMethodData.tokenizationData.token;
            this.debug && console.log('Result', result);
        } catch (error) {
            if (error?.statusCode === 'CANCELLED') {
                this.setCancel(true);
            } else {
                this.setError(error?.statusMessage || error?.message || null);
            }
        }
    }
}

export default GooglePayService;
