// Reusable MutationObserver-based rebinder
// Triggers onRelevantMutations after relevant DOM changes inside a root
// Returns a function to disconnect the observer

export const DEFAULT_REBIND_SELECTORS = [
  '.payment-options',
  "[class*='js-przelewy24-']",
  '#checkout-payment-step',
];

export function startRebindObserver({
  root,
  onRelevantMutations,
  relevantSelectors = DEFAULT_REBIND_SELECTORS,
  debounceMs = 100,
  onlyAddedNodes = false,
}) {
  if (typeof onRelevantMutations !== 'function') {
    // nothing to observe
    return () => {};
  }

  const rootElement = typeof root === 'string' ? document.querySelector(root) : root;
  const targetRoot = rootElement || document.querySelector('#content-wrapper') || document.body;

  let debounceTimer = null;
  const schedule = () => {
    if (debounceTimer) clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => onRelevantMutations(), debounceMs);
  };

  const observer = new MutationObserver((mutations) => {
    let relevantChange = false;

    for (const mutation of mutations) {
      if (mutation.type !== 'childList') continue;

      const nodes = onlyAddedNodes
        ? Array.from(mutation.addedNodes || [])
        : [
            ...Array.from(mutation.addedNodes || []),
            ...Array.from(mutation.removedNodes || []),
          ];

      for (const node of nodes) {
        if (!(node instanceof Element)) continue;

        if (relevantSelectors.some((sel) => node.matches(sel))) {
          relevantChange = true;
          break;
        }

        if (relevantSelectors.some((sel) => node.querySelector(sel))) {
          relevantChange = true;
          break;
        }
      }

      if (relevantChange) break;
    }

    if (relevantChange) schedule();
  });

  observer.observe(targetRoot, { childList: true, subtree: true });

  return () => observer.disconnect();
}
