import useToggleDisplay from "./useToggleDisplay";

const useToggleLoader = () => {

    const { toggle } = useToggleDisplay();

    const toggleLoader = (loaderSelector, display) => {
        const loader = document.querySelector(loaderSelector);

        if (loader) {
            toggle(loader, display);
        }
    }

    return {
        toggleLoader,
    };
}

export default useToggleLoader;
