import { DOMReady } from "./utils/DOMHelpers";
import { startRebindObserver } from "./utils/RebindObserver";
import paymentFormController from "./controller/paymentFormController";
import defaultPaymentSubmitController from "./controller/defaultPaymentSubmitController";
import PaymentFormSelectors from "./selectors/paymentFormSelectorsMap";
import cardController from "./controller/cardController";
import googlePayController from "./controller/googlePayController";
import applePayController from "./controller/applePayController";
import blikController from "./controller/blikController";
import CardService from "./services/CardService";
import useToggleDisplay from "./utils/useToggleDisplay";

(() => {
    let P24CardService = null;

    const { PRZELEWY24_PAYMENT_OPTION_NESTED_INPUT } = PaymentFormSelectors;
    const { hide } = useToggleDisplay();

    const hidePsAgreementsByJs = () => {
        const psAgreements = document.querySelectorAll('.ps-hidden-by-js');

        if (psAgreements.length) {
            psAgreements.forEach((agreement) => {
                hide(agreement);
            });
        }
    }

    const setSupercheckoutFormAction = (url) => {
        if (!url) return;
        const scForm = document.querySelector('#velsof_payment_dialog .velsof_content_section form');
        if (scForm) {
            scForm.action = url;
        }
    };

    const handleNestedChangeForSC = (event) => {
        const url = event && event.currentTarget ? event.currentTarget.value : null;
        setSupercheckoutFormAction(url);
    };

    const attachSupercheckoutFormSync = () => {
        const inputs = document.querySelectorAll(PRZELEWY24_PAYMENT_OPTION_NESTED_INPUT);
        inputs.forEach((input) => {
            input.removeEventListener('change', handleNestedChangeForSC);
            input.addEventListener('change', handleNestedChangeForSC);
        });

        const checked = document.querySelector(`${PRZELEWY24_PAYMENT_OPTION_NESTED_INPUT}:checked`);
        if (checked) {
            setSupercheckoutFormAction(checked.value);
        }
    };


    const initControllers = async () => {
        const { init: initPaymentForm } = paymentFormController();
        const { init: initDefaultPaymentSubmitController } = defaultPaymentSubmitController();
        const { init: initCardController } = cardController();
        const { init: initGooglePayController } = googlePayController();
        const { init: initApplePayController } = applePayController();
        const { init: initBlikController } = blikController();

        if (!P24CardService) {
            const p24ConfigTokenization = window._p24ConfigTokenization || null;

            if (p24ConfigTokenization) {
                P24CardService = new CardService(p24ConfigTokenization);
            }
        }

        try {
            initPaymentForm();
            attachSupercheckoutFormSync();
            initDefaultPaymentSubmitController();
            await initCardController(P24CardService);
            await initGooglePayController(P24CardService);
            await initApplePayController(P24CardService);
            initBlikController();
            hidePsAgreementsByJs();
        } catch (e) {
            // eslint-disable-next-line no-console
            console.warn('[P24 Supercheckout] Controller init failed:', e);
        }
    };

    let stopObserver = null;
    let currentObserverRoot = null;

    const reinitOnMutations = () => {
        if (typeof stopObserver === 'function') {
            stopObserver();
            stopObserver = null;
        }
        Promise.resolve(initControllers())
            .finally(() => {
                attachSupercheckoutFormSync();

                if (currentObserverRoot) {
                    startObserver(currentObserverRoot);
                }
            });
    };

    const startObserver = (root) => {
        if (typeof stopObserver === 'function') {
            stopObserver();
        }
        currentObserverRoot = root;
        stopObserver = startRebindObserver({
            root,
            onRelevantMutations: reinitOnMutations,
            relevantSelectors: [
                '.payment-options',
                PRZELEWY24_PAYMENT_OPTION_NESTED_INPUT,
            ],
            debounceMs: 200,
            onlyAddedNodes: true,
        });
    };

    const init = async () => {
        startObserver('#supercheckout-fieldset');
    };

    DOMReady(init);
})();
