import DOM_SELECTORS from "../selectors/blikSelectorsMap";
import { getPayloadToUrl } from "../utils/urlHelpers";

import useForm from "../components/useForm";
import useToggleLoader from "../utils/useToggleLoader";
import useNotice from "../components/useNotice";
import useToggleDisplay from "../utils/useToggleDisplay";
import paymentHelper from "../utils/usePaymentHelper";
import useModals from "../utils/useModals";
import useOneClickPaymentHelper from "../utils/useOneClickPaymentHelper";

const blikController = () => {
    let p24Notices = null;

    const {
        PRZELEWY24_BLIK_WRAPPER,
        PRZELEWY24_BLIK_NOTICE_WRAPPER,
        PRZELEWY24_BLIK_PAYMENT_INPUT,
        PRZELEWY24_BLIK_WHITE_LABEL_WRAPPER,
        PRZELEWY24_BLIK_WHITE_LABEL_LOADER,
        PRZELEWY24_BLIK_WHITE_LABEL_ID,
        PRZELEWY24_BLIK_SUBMIT_WRAPPER_LOADER,
        PRZELEWY24_BLIK_REGULATIONS_WRAPPER,
        PRZELEWY24_BLIK_CODE_INPUT,
        PRZELEWY24_BLIK_SUBMIT_BUTTON,
    } = DOM_SELECTORS;

    const { show, hide,toggle } = useToggleDisplay();
    const { getSelectedPaymentOption, getUrlFormFromPaymentOption, getRegulations } = paymentHelper();
    const { registerBlikTransaction, registerBlikCode } = useForm();
    const { showNotice, hideNotice } = useNotice();
    const { toggleLoader } = useToggleLoader();
    const { showCardWhiteLabelModal, hideCardWhiteLabelModal } = useModals();
    const { ensureAddressesAreSaved } = useOneClickPaymentHelper();

    const validateSubmitButton = (submitWrapper) => {
        if (!submitWrapper) return;

        const submitButton = submitWrapper.querySelector(PRZELEWY24_BLIK_SUBMIT_BUTTON);
        if (!submitButton) return;

        const codeInput = submitWrapper.querySelector(PRZELEWY24_BLIK_CODE_INPUT);
        const regulationsWrapper = submitWrapper.querySelector(PRZELEWY24_BLIK_REGULATIONS_WRAPPER);

        let isCodeValid = false;
        if (codeInput) {
            const numericValue = codeInput.value.replace(/[^0-9]/g, '');
            isCodeValid = numericValue.length === 6;
        }

        let isRegulationsChecked = false;
        if (regulationsWrapper) {
            const regulations = getRegulations(regulationsWrapper);
            isRegulationsChecked = Object.values(regulations).every((value) => value);
        }

        if (isCodeValid && isRegulationsChecked) {
            submitButton.removeAttribute('disabled');
        } else {
            submitButton.setAttribute('disabled', 'disabled');
        }
    };

    const handleRegulationsChange = (event) => {
        const regulationsWrapper = event.target.closest(PRZELEWY24_BLIK_REGULATIONS_WRAPPER);
        const submitWrapper = regulationsWrapper?.closest(PRZELEWY24_BLIK_WRAPPER);

        validateSubmitButton(submitWrapper);
    }

    const handleBlikTransactionResponse = (status, message, urlReturn) => {
        switch (status) {
            case 'success':
                if (urlReturn) {
                    showNotice(PRZELEWY24_BLIK_NOTICE_WRAPPER, message, 'success');
                    setTimeout(() => {
                        window.location.href = urlReturn;
                    }, 2000);
                } else {
                    showNotice(
                        PRZELEWY24_BLIK_NOTICE_WRAPPER,
                        p24Notices?.transactionError || 'Error while processing transaction.',
                        'danger'
                    );
                }
                break;
            case 'pending':
                showNotice(
                    PRZELEWY24_BLIK_NOTICE_WRAPPER,
                    p24Notices?.blikPaymentWarning || 'We were unable to confirm your payment. Please try again or choose another payment method.',
                    'warning'
                );
                break;
            case 'error':
                showNotice(PRZELEWY24_BLIK_NOTICE_WRAPPER, message, 'danger');
                break;
            default:
                showNotice(
                    PRZELEWY24_BLIK_NOTICE_WRAPPER,
                    p24Notices?.blikPaymentWarning || 'We were unable to confirm your payment. Please try again or choose another payment method.',
                    'warning'
                );
        }
    }

    const registerBlikFetch = async (url) => await registerBlikTransaction(url, 1, 5000);

    const handleRegisterBlikTransaction = async (payload, url) => {
        let urlBlikAjax, urlForm, urlReturn;
        const payloadUrl = getPayloadToUrl(payload);

        urlForm = url || getUrlFormFromPaymentOption(getSelectedPaymentOption());

        try {
            const response = await registerBlikCode(urlForm, payloadUrl);

            if (response?.errors) {
                showNotice(PRZELEWY24_BLIK_NOTICE_WRAPPER, response?.errors, 'danger');
            } else {
                urlBlikAjax = response?.urlBlikAjax;
                urlReturn = response?.urlReturn;
            }
        } catch (errorResponse) {
            if (errorResponse.error) {
                console.error(errorResponse.error);
            } else {
                console.error(errorResponse);
            }

            showNotice(
                PRZELEWY24_BLIK_NOTICE_WRAPPER,
                p24Notices?.transactionError || 'Error while processing transaction.',
                'danger'
            );
        }

        return { urlBlikAjax, urlReturn }
    }

    const handleBlikSubmitTransaction = async (payload, url = '') => {
        const { urlBlikAjax, urlReturn } = await handleRegisterBlikTransaction(payload, url);
        let status = '';

        if (!urlBlikAjax || !urlReturn) {
            console.error('urlBlikAjax or urlReturn is missing.');
            return;
        }

        showCardWhiteLabelModal(PRZELEWY24_BLIK_WHITE_LABEL_WRAPPER);

        await registerBlikFetch(urlBlikAjax).then((response) => {
            if (!response || !response.status || !response.completed) {
                showNotice(
                    PRZELEWY24_BLIK_NOTICE_WRAPPER,
                    p24Notices?.blikPaymentWarning || 'We were unable to confirm your payment. Please try again or choose another payment method.',
                    'warning'
                );
                return;
            }

            handleBlikTransactionResponse(response.status, response.message, urlReturn);
            status = response.status;
        });

        hideCardWhiteLabelModal(PRZELEWY24_BLIK_WHITE_LABEL_WRAPPER);

        return status;
    }

    const handleBlikSubmit = async (event) => {
        event.preventDefault();
        hideNotice(PRZELEWY24_BLIK_NOTICE_WRAPPER);

        // CRITICAL: Ensure addresses are saved before processing BLIK payment (module-aware)
        console.log('[BLIK] Checking if address saving is required for current checkout module...');
        const addressesSaved = await ensureAddressesAreSaved();

        if (!addressesSaved) {
            console.error('[BLIK] Cannot proceed - addresses are not saved or validation failed');
            showNotice(
                PRZELEWY24_BLIK_NOTICE_WRAPPER,
                p24Notices?.addressError || 'Please complete your address information before proceeding with payment.',
                'danger'
            );
            return;
        }

        console.log('[BLIK] Address requirements satisfied, proceeding with BLIK payment...');

        const submitWrapper = event.target.closest(PRZELEWY24_BLIK_WRAPPER);
        const submitButton = submitWrapper?.querySelector(PRZELEWY24_BLIK_SUBMIT_BUTTON);
        const codeInput = submitWrapper?.querySelector(PRZELEWY24_BLIK_CODE_INPUT);
        const regulationsWrapper = submitWrapper?.querySelector(PRZELEWY24_BLIK_REGULATIONS_WRAPPER);
        const url = submitWrapper?.dataset.url;
        const regulations = getRegulations(regulationsWrapper);

        if (!submitButton || !codeInput || !url) {
            console.error('Submit button, code input or url is missing.');
            showNotice(
                PRZELEWY24_BLIK_NOTICE_WRAPPER,
                p24Notices?.transactionError || 'Error while processing transaction.',
                'danger'
            );
            return;
        }

        submitButton.setAttribute('disabled', 'disabled');
        toggleLoader(PRZELEWY24_BLIK_SUBMIT_WRAPPER_LOADER, true);

        const payload = {
            p24_blik_code: codeInput.value,
            ...regulations
        }

        const statusBlikTransaction = await handleBlikSubmitTransaction(payload, url);

        if (statusBlikTransaction !== 'success') {
            submitButton.removeAttribute('disabled');
            toggleLoader(PRZELEWY24_BLIK_SUBMIT_WRAPPER_LOADER, false);
        }
    }

    const handleCodeInput = (event) => {
        const codeInput = event.target;

        if (!codeInput) {
            console.error('Code input is missing.');
            return;
        }

        const code = codeInput.value;
        const submitWrapper = codeInput.closest(PRZELEWY24_BLIK_WRAPPER);
        codeInput.value = code.replace(/[^0-9]/g, '');

        validateSubmitButton(submitWrapper);
    }

    const attachEvents = () => {
        document.querySelector(PRZELEWY24_BLIK_CODE_INPUT)?.removeEventListener('input', handleCodeInput);
        document.querySelector(PRZELEWY24_BLIK_CODE_INPUT)?.addEventListener('input', handleCodeInput);

        document.querySelectorAll(PRZELEWY24_BLIK_REGULATIONS_WRAPPER)?.forEach((regulationsWrapper) => {
            regulationsWrapper.querySelectorAll('input[type="checkbox"]')?.forEach((input) => {
                input.removeEventListener('change', handleRegulationsChange);
                input.addEventListener('change', handleRegulationsChange);
            });
        });

        document.querySelector(PRZELEWY24_BLIK_SUBMIT_BUTTON)?.removeEventListener('click', handleBlikSubmit);
        document.querySelector(PRZELEWY24_BLIK_SUBMIT_BUTTON)?.addEventListener('click', handleBlikSubmit);
    }

    const init = () => {
        const blikAvailable = document.querySelector(PRZELEWY24_BLIK_PAYMENT_INPUT);

        p24Notices = window.p24Notices || null;

        if (blikAvailable) {
            attachEvents();
        }
    }

    return { init }
}

export default blikController;
