import DOM_SELECTORS from "../selectors/applePaySelectorsMap";
import BasePaymentService from "./BasePaymentService";
import { loadExternalScript } from "../utils/loadExternalScript";

class ApplePayService extends BasePaymentService {
    constructor(config) {
        super();

        const {
            merchantId,
            mode = 'sandbox',
            options
        } = config;

        const { apple } = options;
        const { appleMerchantId, appleMerchantName, appleCountryCode, appleLocale, appleValidateUrl } = apple;

        this.session = null;
        this.validateUrl = appleValidateUrl;
        this.buttonWrapper = DOM_SELECTORS.PRZELEWY24_APPLE_PAY_WRAPPER;

        this.merchantId = appleMerchantId;
        this.merchantName = appleMerchantName;
        this.countryCode = appleCountryCode;
        this.locale = appleLocale;

        this.merchantCapabilities = ["supports3DS", "supportsCredit", "supportsDebit"];
        this.allowedCardNetworks = ["visa", "masterCard", "amex", "discover"];
    }

    async init() {
        await loadExternalScript('apple-pay', 'https://applepay.cdn-apple.com/jsapi/1.latest/apple-pay-sdk.js', () => this.createClient());
    }

    async isPaymentAvailable() {
        const client = this.createClient();

        if (!client) {
            return false;
        }

        try {
            return await client.canMakePayments();
        } catch (error) {
            console.error('Error:', error);
            return false;
        }
    }

    createClient() {
        if (this.paymentClient === null && window.ApplePaySession) {
            this.paymentClient = window.ApplePaySession;
        }

        return this.paymentClient;
    }

    createPaymentButton(onClick = () => {}) {
        const button = document.createElement('apple-pay-button');
        button.setAttribute('buttonstyle', 'black');
        button.setAttribute('type', 'buy');
        button.setAttribute('locale', this.locale);
        button.addEventListener('click', onClick);

        const wrapper = document.querySelector(this.buttonWrapper);
        wrapper && wrapper.appendChild(button);

        return true;
    }

    getPaymentRequest() {
        const { merchantName, countryCode, paymentDetails } = this;
        const { total, currency } = paymentDetails;

        const request = {
            "countryCode": countryCode,
            "currencyCode": currency,
            "merchantCapabilities": this.merchantCapabilities,
            "supportedNetworks": this.allowedCardNetworks,
            "total": {
                "label": merchantName,
                "type": "final",
                "amount": total
            }
        };

        return request;
    }

    addListenersToSession() {
        this.session.onvalidatemerchant = event => {
            console.log('Validate merchant event:', event);
            this.validateMerchant();
        }

        this.session.onpaymentauthorized = event => {
            console.log('Payment authorized event:', event);
            this.token = JSON.stringify(event.payment.token.paymentData);
            this.complete(true);
            this.resolve(true);
        }

        this.session.oncancel = event => {
            console.log('Payment cancelled event:', event);
            this.complete(false);
            this.reject('Payment session cancelled');
        }
    }

    complete(status) {
        const result = {
            status: status ? ApplePaySession.STATUS_SUCCESS : ApplePaySession.STATUS_FAILURE
        }

        this.session.completePayment(result);
    }

    async validateMerchant() {
        try {
            let request = await fetch(this.validateUrl);
            const response = await request.json();
            response && this.session.completeMerchantValidation(response);
        } catch (error) {
            this.reject(error);
        }
    }

    async processPayment() {
        this.reset();
        const client = this.createClient();

        try {
            await new Promise(async (resolve, reject) => {
                this.session = new client(14, this.getPaymentRequest());
                this.resolve = resolve;
                this.reject = reject;
                this.addListenersToSession();
                this.session.begin();
            });
        } catch (error) {
            if (error === 'CANCELLED') {
                this.setCancel(true);
            } else {
                this.setError(error || null);
            }
        }
    }
}

export default ApplePayService;
