export default class BasePaymentService {
    constructor() {
        this.reset()

        this.paymentDetails = { total: '0.00', currency: '' }
        this.paymentClient = null
        this.token = null
        this.cancel = false
        this.debug = false
    }

    reset() {
        this.error = false
        this.errorMessage = null
        this.cancel = false
        this.token = null
    }

    setError(message) {
        this.error = true
        this.errorMessage = message
        this.debug && console.error('Error in payment service:', message)
    }

    getError() {
        return this.errorMessage
    }

    hasError() {
        return this.error
    }

    setCancel(value) {
        this.cancel = value
    }

    isCanceled() {
        return this.cancel
    }

    setPaymentDetails(total, currency) {
        this.paymentDetails = {
            total: parseFloat(total).toFixed(2).toString(),
            currency
        }
    }

    getPaymentData() {
        return this.token ?? false
    }
}
