import DOM_SELECTORS from '../selectors/cardSelectorsMap';

const usePaymentHelper = () => {
    const {
        PAYMENT_OPTION_FORM,
        PAYMENT_OPTION_INPUT_NAME,
        PAYMENT_OPTION_WRAPPER,
        PRZELEWY24_SAVED_CARDS_INPUT,
    } = DOM_SELECTORS;

    const getSelectedCard = () => {
        return document.querySelector(`${PRZELEWY24_SAVED_CARDS_INPUT}:checked`);
    }

    const getSelectedPaymentOption = () => {
        return document.querySelector(`input[name="${PAYMENT_OPTION_INPUT_NAME}"]:checked`);
    }

    const getPaymentId = (paymentOption) => {
        return paymentOption.id;
    }

    const getPaymentWrapperFromChild = (child) => {
        return child.closest(PAYMENT_OPTION_WRAPPER);
    }

    const getPaymentFormFromPaymentMethod = (paymentOption) => {
        const paymentId = getPaymentId(paymentOption);
        const wrapper = getPaymentWrapperFromChild(paymentOption);

        return wrapper.querySelector(`${PAYMENT_OPTION_FORM}[id*="${paymentId}"] form`);
    }

    const getUrlFormFromPaymentOption = (paymentOption) => {
        const form = getPaymentFormFromPaymentMethod(paymentOption);

        return form.action;
    }

    const getRegulations = (regulationsWrapper) => {
        if (!regulationsWrapper) {
            return {};
        }

        const regulationInputs = regulationsWrapper?.querySelectorAll('input[type="checkbox"]');
        const regulations = {};

        regulationInputs?.forEach((input) => {
            regulations[input.name] = input.checked;
        });

        return regulations;
    }

    return {
        getSelectedCard,
        getSelectedPaymentOption,
        getPaymentId,
        getPaymentWrapperFromChild,
        getPaymentFormFromPaymentMethod,
        getUrlFormFromPaymentOption,
        getRegulations,
    };
}

export default usePaymentHelper;
