import wretch from 'wretch';
import FormUrlAddon from "wretch/addons/formUrl";
import usePoll from "./usePoll";

const useForm = () => {

    const {
        poll,
    } = usePoll();

    const getValidation = result => !result.completed;

    const fetchRegisterTransaction = (url, pollCount) => new Promise((resolve, reject) => {
        wretch(url)
            .addon(FormUrlAddon)
            .formUrl({try: pollCount})
            .post()
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }

                reject(new Error('An error occurred while registering the transaction.'));
            });
    });

    const fetchRegisterBlikTransaction = (url, pollCount) => new Promise((resolve, reject) => {
        wretch(url)
            .addon(FormUrlAddon)
            .formUrl({try: pollCount})
            .post()
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }

                reject(new Error('An error occurred while registering the transaction.'));
            });
    });

    const registerTransaction = async (url = '', pollCount = 1, timeout = 5000) => {
        const request = (response = null) => fetchRegisterTransaction(url, response?.nextTry || pollCount);

        return await poll(request, getValidation, timeout);
    };

    const registerBlikTransaction = async (url = '', pollCount = 1, timeout = 5000) => {
        const request = (response = null) => fetchRegisterBlikTransaction(url, response?.nextTry || pollCount);

        return await poll(request, getValidation, timeout);
    };

    const registerBlikCode = async (url = '', formData = '') => new Promise((resolve, reject) => {
        wretch(url)
            .addon(FormUrlAddon)
            .formUrl(formData + `&ajax=1`)
            .post()
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }

                reject(new Error('An error occurred while registering the blik transaction.'));
            });
    });

    const registerCardTransaction = async (url = '', formData = '') => new Promise((resolve, reject) => {
        wretch(url)
            .addon(FormUrlAddon)
            .formUrl(formData + `&ajax=1`)
            .post()
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }

                reject(new Error('An error occurred while registering the card transaction.'));
            });
    });

    return {
        registerTransaction,
        registerCardTransaction,
        registerBlikTransaction,
        registerBlikCode
    };
};

export default useForm;
